const body = $input.first().json.body || $input.first().json;

// Could come from Supabase webhook or portal POST
let application;
if (body.record) {
  application = body.record;
} else {
  application = body;
}

const status = application.status;
if (!status || !['approved', 'rejected'].includes(status)) {
  throw new Error('Invalid status: ' + status + '. Expected approved or rejected.');
}

return [{
  json: {
    application_id: application.id,
    application_number: application.application_number || 'N/A',
    status: status,
    first_name: application.first_name,
    last_name: application.last_name,
    email: application.email,
    phone: application.phone,
    program_id: application.program_id,
    rejection_reason: application.rejection_reason || '',
    full_name: `${application.first_name} ${application.last_name}`,
    timestamp_est: new Date().toLocaleString('en-US', {
      timeZone: 'America/New_York',
      dateStyle: 'medium',
      timeStyle: 'short'
    })
  }
}];

